以下是使用 Java 开发的 PayPal 支付成功后的验证代码示例，使用 PayPal 的 IPN（Instant Payment Notification）机制来实现验证：

```java
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.io.PrintWriter;
import java.util.HashMap;
import java.util.Iterator;
import java.util.Map;

public class PaypalIPN {

    private static final String VERIFY_URI = "https://ipnpb.sandbox.paypal.com/cgi-bin/webscr";

    // 验证 PayPaI 支付信息是否有效
    public boolean verifyPaypalIPN(HttpServletRequest request) throws Exception {
        // 从request中读取支付信息
        Map<String, String> params = readPaypalParams(request);

        // 添加通知验证标识（NV）到参数
        params.put("cmd", "_notify-validate");

        // 发送 HTTP POST 请求
        String response = sendHttpPostRequest(VERIFY_URI, params);

        // 验证 Paypal 是否返回了一个有效的HTTP状态码
        if (response == null || response.length() == 0) {
            throw new Exception("Invalid response from PayPal");
        }

        // 验证 PayPal 响应中的校验结果
        if (response.equals("VERIFIED")) {
            // TODO: 验证成功，更新订单状态、发货等操作
            return true;
        } else {
            // TODO: 验证失败，记录错误日志等操作
            return false;
        }
    }

    // 从request中读取PayPal支付参数
    private Map<String, String> readPaypalParams(HttpServletRequest request) throws IOException {
        Map<String, String> params = new HashMap<>();
        request.setCharacterEncoding("UTF-8");
        Iterator<String> iter = request.getParameterMap().keySet().iterator();
        while (iter.hasNext()) {
            String name = iter.next();
            String[] values = request.getParameterMap().get(name);
            StringBuilder valueStr = new StringBuilder();
            for (int i = 0; i < values.length; i++) {
                valueStr.append(values[i]);
            }
            params.put(name, valueStr.toString());
        }
        return params;
    }

    // 发送 POST 请求并获取响应
    private String sendHttpPostRequest(String url, Map<String, String> params) throws Exception {
        HttpURLConnection conn = null;
        PrintWriter writer = null;
        BufferedReader reader = null;
        StringBuilder resultBuf = new StringBuilder();

        // 配置连接
        conn = (HttpURLConnection) new URL(url).openConnection();
        conn.setRequestMethod("POST");
        conn.setDoOutput(true);
        conn.setDoInput(true);
        conn.setRequestProperty("Content-Type", "application/x-www-form-urlencoded");

        // 构建请求参数
        StringBuilder paramsBuf = new StringBuilder();
        for (Map.Entry<String, String> entry : params.entrySet()) {
            paramsBuf.append(entry.getKey()).append("=").append(URLEncoder.encode(entry.getValue(), "UTF-8")).append("&");
        }
        paramsBuf.deleteCharAt(paramsBuf.length() - 1);

        // 发送请求数据
        writer = new PrintWriter(new OutputStreamWriter(conn.getOutputStream(), "UTF-8"));
        writer.print(paramsBuf.toString());
        writer.flush();

        // 读取响应数据
        reader = new BufferedReader(new InputStreamReader(conn.getInputStream(), "UTF-8"));
        String line;
        while ((line = reader.readLine()) != null) {
            resultBuf.append(line);
        }
        reader.close();

        // 关闭连接
        conn.disconnect();

        return resultBuf.toString();
    }
}
```

上述代码中，我们使用一个 `verifyPaypalIPN()` 方法来验证 PayPal 的 IPN 通知。首先，从 HttpServletRequest 中获取支付信息，并添加 `_notify-validate` 参数（通知验证标识）。然后，我们向 PayPal 发送一个 POST 请求，使用 `sendHttpPostRequest()` 方法。在接收到 PayPal 的响应后，我们验证响应的状态，如果响应状态为 "VERIFIED"，则认为 PayPal 的支付请求是真实有效的。如果响应状态为 "INVALID"，则表示该请求无效。最后，我们可以返回 true 或 false，以便进行相应的操作，例如更新订单状态、发货等等。

